mapper.select:
select id, config_code, config_name, owner_id, owner_code, owner_name, platform_code, platform_name, customer_id, vendor_id, app_key, app_secret,
access_token, access_token_expired, refresh_token, group_id, service_provider_id, service_provider_name, state, remark, created_by, created_name,
created_date, modified_by, modified_name, modified_date, version, deleted_flag
from base_platform_auth bpa
where bpa.deleted_flag = 0

    and bpa.group_id = #{groupId}


    and bpa.service_provider_id = #{serviceProviderId}


    and bpa.service_provider_id in

        #{item}



    and bpa.owner_id = #{ownerId}


    and bpa.owner_id in

        #{item}



    and bpa.state = #{state}


    and bpa.config_code like concat('%', concat(#{configCode}, '%'))


    and bpa.platform_code = #{platformCode}


    and bpa.platform_code in

        #{item}



    and bpa.id = #{id}


    and bpa.id in

        #{item}



    and bpa.access_token_expired > #{expireDateStart}


    and bpa.access_token_expired < #{expireDateEnd}


    and bpa.created_date > #{createdDateBegin}


    and bpa.created_date < #{createdDateEnd}


    and bpa.modified_date > #{modifiedDateBegin}


    and bpa.modified_date < #{modifiedDateEnd}

order by bpa.created_date desc

mapper.update:
update base_platform_auth
config_code = #{configCode}, config_name = #{configName}, owner_id = #{ownerId}, owner_code = #{ownerCode}, owner_name = #{ownerName}, platform_code = #{platformCode}, platform_name = #{platformName}, customer_id = #{customerId}, vendor_id = #{vendorId}, app_key = #{appKey}, app_secret = #{appSecret}, access_token = #{accessToken}, access_token_expired = #{accessTokenExpired}, refresh_token = #{refreshToken}, remark = #{remark},
version = version + 1, modified_by = #{modifiedBy}, modified_name = #{modifiedName}, modified_date = #{modifiedDate},
where id = #{id}
and version = #{version}
